import type { ScanResult } from './types'
import type { SecurityGrade } from '../securityTypes'
import { getGrade } from '../securityScoring'

export const scanKey = (address: string, chainId: string) => `${address}:${chainId}`

/** Maximum time a single scanner is allowed to run before being rejected. */
export const SCANNER_TIMEOUT_MS = 15_000

/**
 * Wraps a scanner promise with a timeout. If the scanner doesn't resolve within
 * SCANNER_TIMEOUT_MS, the returned promise rejects with "Scanner timed out".
 * Protects the scan queue from hanging on a slow/unresponsive scanner.
 */
export const withScannerTimeout = <T>(promise: Promise<T>): Promise<T> =>
  Promise.race([
    promise,
    new Promise<never>((_, reject) => setTimeout(() => reject(new Error('Scanner timed out')), SCANNER_TIMEOUT_MS)),
  ])

export const formatTimestamp = (ts?: number): string => {
  if (!ts) return '—'
  const now = Date.now()
  const diff = now - ts
  if (diff < 60_000) return 'Just now'
  if (diff < 3_600_000) return `${Math.floor(diff / 60_000)}m ago`
  if (diff < 86_400_000) return `${Math.floor(diff / 3_600_000)}h ago`
  return new Date(ts).toLocaleDateString()
}

export type GradeSummary = {
  passing: number
  applicableCount: number
  grade: SecurityGrade
  hasCriticalIssue: boolean
}

export const computeSummary = (results: Record<string, ScanResult>): GradeSummary | null => {
  const entries = Object.values(results)
  const applicable = entries.filter((r) => r.status !== 'not_applicable' && r.status !== 'inconclusive')
  if (applicable.length === 0) return null

  const passing = applicable.filter((r) => r.status === 'clear').length
  const hasCriticalIssue = applicable.some((r) => r.severity === 'Critical')
  const clearRatio = passing / applicable.length

  return { passing, applicableCount: applicable.length, grade: getGrade(clearRatio), hasCriticalIssue }
}

export const severityRank = (severity: string): number => {
  const order: Record<string, number> = { Critical: 0, High: 1, Medium: 2, Low: 3 }
  return order[severity] ?? 4
}

/** Per-Safe grade based on its worst check result. */
export type SafeGrade = 'critical' | 'at_risk' | 'needs_attention' | 'passing'

export const getSafeGrade = (results: Record<string, ScanResult>): SafeGrade => {
  let hasIssue = false
  let hasPartial = false

  for (const result of Object.values(results)) {
    if (result.status === 'not_applicable' || result.status === 'inconclusive') continue
    if (result.severity === 'Critical') return 'critical'
    if (result.status === 'issue') hasIssue = true
    if (result.status === 'partial') hasPartial = true
  }

  if (hasIssue) return 'at_risk'
  if (hasPartial) return 'needs_attention'
  return 'passing'
}

import type { SecurityScanner } from './types'

export const accountSetupScanner: SecurityScanner = {
  id: 'account_setup',
  scan: async (ctx) => {
    const { owners, threshold } = ctx
    const ownerCount = owners.length
    const now = new Date().toISOString()

    if (ownerCount === 0) {
      return {
        status: 'partial',
        severity: 'Medium',
        score: 50,
        evidence: ['Signer data not yet available'],
        remediation: 'Open this Safe directly to load signer information.',
        lastChecked: now,
      }
    }

    // Single signer = no multisig protection
    if (ownerCount === 1) {
      return {
        status: 'issue',
        severity: 'Critical',
        score: 10,
        evidence: [
          { label: 'Signers', value: String(ownerCount) },
          { label: 'Threshold', value: `${threshold} of ${ownerCount}` },
        ],
        remediation: 'Add additional signers and increase the threshold for better security.',
        lastChecked: now,
      }
    }

    // Threshold of 1 with multiple owners = any single signer can execute
    if (threshold === 1) {
      return {
        status: 'issue',
        severity: 'Critical',
        score: 15,
        evidence: [
          { label: 'Signers', value: String(ownerCount) },
          { label: 'Threshold', value: `${threshold} of ${ownerCount}` },
          'Any single signer can approve transactions',
        ],
        remediation: `Increase the threshold to at least ${Math.ceil(ownerCount / 2)} of ${ownerCount}.`,
        lastChecked: now,
      }
    }

    // Threshold below simple majority = suboptimal
    const simpleMajority = Math.ceil(ownerCount / 2)
    if (threshold < simpleMajority) {
      return {
        status: 'partial',
        severity: 'Medium',
        score: 60,
        evidence: [
          { label: 'Signers', value: String(ownerCount) },
          { label: 'Threshold', value: `${threshold} of ${ownerCount}` },
          { label: 'Recommended', value: `at least ${simpleMajority} of ${ownerCount}` },
        ],
        remediation: `Consider increasing the threshold to ${simpleMajority} of ${ownerCount} for stronger security.`,
        lastChecked: now,
      }
    }

    // Good setup: threshold >= simple majority
    return {
      status: 'clear',
      severity: 'Low',
      score: 100,
      evidence: [
        { label: 'Signers', value: String(ownerCount) },
        { label: 'Threshold', value: `${threshold} of ${ownerCount}` },
      ],
      remediation: '',
      lastChecked: now,
    }
  },
}

import { ContractVersions, KnownContracts, type SupportedNetworks } from '@gnosis.pm/zodiac'
import { sameAddress } from '@safe-global/utils/utils/addresses'
import type { SecurityScanner } from './types'
import { ZERO_ADDRESS, HIGH_VALUE_THRESHOLD_USD } from './constants'

/** Name fragments that identify a trusted guard (case-insensitive match). */
const TRUSTED_GUARD_NAMES = ['hypernative', 'scope guard', 'meta guard']

/** Zodiac guard contracts to check addresses against. */
const ZODIAC_GUARD_CONTRACTS = [KnownContracts.SCOPE_GUARD, KnownContracts.META_GUARD]

/** Check if a guard address matches a known Zodiac guard deployment. */
const isKnownZodiacGuard = (chainId: string, guardAddress: string): boolean => {
  try {
    const chainContracts = ContractVersions[Number(chainId) as SupportedNetworks]
    if (!chainContracts) return false

    return ZODIAC_GUARD_CONTRACTS.some((contract) => {
      const versions = chainContracts[contract]
      return versions && Object.values(versions).some((addr) => sameAddress(addr, guardAddress))
    })
  } catch {
    return false
  }
}

const isHypernativeGuard = (name?: string | null): boolean => {
  if (!name) return false
  return name.toLowerCase().includes('hypernative')
}

/**
 * Two-layer trust detection:
 * Layer 1: Name-based matching from CGW API enrichment
 * Layer 2: Address-based matching against Zodiac guard deployments
 */
const isTrustedGuard = (name: string | null | undefined, chainId: string, address: string): boolean => {
  // Layer 1: API-provided name
  if (name) {
    const lower = name.toLowerCase()
    if (TRUSTED_GUARD_NAMES.some((trusted) => lower.includes(trusted))) return true
  }

  // Layer 2: Known Zodiac guard deployment addresses
  return isKnownZodiacGuard(chainId, address)
}

export const guardScanner: SecurityScanner = {
  id: 'guard',
  scan: async (ctx) => {
    const { guard, chainId, chainSupportsHypernative } = ctx
    const now = new Date().toISOString()

    const hasGuard = guard !== null && guard.value !== ZERO_ADDRESS

    // Tier 1: Untrusted guard detected
    if (hasGuard && !isTrustedGuard(guard.name, chainId, guard.value)) {
      const guardLabel = guard.name || `${guard.value.slice(0, 10)}...`
      return {
        status: 'issue',
        severity: 'High',
        score: 30,
        evidence: [
          { label: 'Guard', value: guardLabel },
          { label: 'Status', value: 'Unverified guard contract' },
        ],
        remediation:
          'A transaction guard is set but could not be verified as trusted. Review it in Settings to ensure it is from a recognized provider.',
        lastChecked: now,
        ctaLabelOverride: 'Review modules',
      }
    }

    // Tier 2: Known trusted guard
    if (hasGuard && isTrustedGuard(guard.name, chainId, guard.value)) {
      const isHypernative = isHypernativeGuard(guard.name)
      return {
        status: 'clear',
        severity: 'Low',
        score: 100,
        evidence: [
          { label: 'Guard', value: guard.name ?? 'Trusted Guard' },
          { label: 'Status', value: 'Active protection' },
        ],
        remediation: '',
        lastChecked: now,
        ...(isHypernative ? { partner: 'hypernative' as const } : {}),
      }
    }

    // Tier 3: No guard, high-value Safe on a chain that supports enterprise-grade protection
    if (!hasGuard && chainSupportsHypernative && ctx.balanceUsd > HIGH_VALUE_THRESHOLD_USD) {
      return {
        status: 'partial',
        severity: 'Medium',
        score: 60,
        evidence: [{ label: 'Status', value: 'No transaction guard configured' }],
        remediation:
          'For high-value accounts, a transaction guard adds pre-execution validation. Enterprise-grade protection is available.',
        lastChecked: now,
        ctaLabelOverride: 'Learn more',
        partner: 'hypernative',
      }
    }

    // Tier 4: No guard — normal (low-value Safe or unsupported chain)
    return {
      status: 'clear',
      severity: 'Low',
      score: 100,
      evidence: [{ label: 'Status', value: 'No guard required' }],
      remediation: '',
      lastChecked: now,
    }
  },
}

import { ContractVersions, KnownContracts, type SupportedNetworks } from '@gnosis.pm/zodiac'
import { getAllowanceModuleDeployment } from '@safe-global/safe-modules-deployments'
import { sameAddress } from '@safe-global/utils/utils/addresses'
import type { SecurityScanner } from './types'
import { ZERO_ADDRESS } from './constants'

/**
 * Known module name fragments (case-insensitive).
 * CGW API enriches known contracts with descriptive names.
 */
const KNOWN_MODULE_NAMES = [
  'delay',
  'allowance',
  'spending limit',
  'roles',
  'scope guard',
  'bridge',
  'reality',
  'optimistic',
  'exit',
  'connext',
]

/**
 * Name-only variant of the module trust check. Returns true if the module name
 * contains a known fragment (case-insensitive). Exposed so the UI can mark
 * individual modules as trusted without rerunning the full scanner.
 */
export const isKnownModuleByName = (name?: string | null): boolean => {
  if (!name) return false
  const lower = name.toLowerCase()
  return KNOWN_MODULE_NAMES.some((known) => lower.includes(known))
}

/**
 * Check if a module address matches a known Zodiac deployment.
 */
const isKnownZodiacModule = (chainId: string, moduleAddress: string): boolean => {
  try {
    const chainContracts = ContractVersions[Number(chainId) as SupportedNetworks]
    if (!chainContracts) return false

    for (const contract of Object.values(KnownContracts)) {
      const versions = chainContracts[contract]
      if (versions && Object.values(versions).some((addr) => sameAddress(addr, moduleAddress))) {
        return true
      }
    }
  } catch {
    // Chain not in Zodiac's SupportedNetworks
  }

  return false
}

/**
 * Check if a module address matches a known Safe Allowance Module deployment.
 */
const isKnownAllowanceModule = (chainId: string, moduleAddress: string): boolean => {
  for (const version of ['0.1.0', '0.1.1']) {
    const deployment = getAllowanceModuleDeployment({ version })
    const addr = deployment?.networkAddresses[chainId]
    if (addr && sameAddress(addr, moduleAddress)) {
      return true
    }
  }
  return false
}

/**
 * Two-layer detection: name from CGW API, then address matching against
 * known Zodiac and Safe module deployments.
 */
const isKnownModule = (chainId: string, moduleAddress: string, moduleName?: string | null): boolean => {
  // Layer 1: API-provided name
  if (isKnownModuleByName(moduleName)) return true

  // Layer 2: Known deployment addresses
  return isKnownZodiacModule(chainId, moduleAddress) || isKnownAllowanceModule(chainId, moduleAddress)
}

export const modulesScanner: SecurityScanner = {
  id: 'modules',
  scan: async (ctx) => {
    const { modules, chainId } = ctx
    const now = new Date().toISOString()

    const activeModules = (modules ?? []).filter((m) => m.value !== ZERO_ADDRESS)

    // Tier 1: No modules — perfectly fine for most Safes
    if (activeModules.length === 0) {
      return {
        status: 'clear',
        severity: 'Low',
        score: 100,
        evidence: [{ label: 'Status', value: 'No modules installed' }],
        remediation: '',
        lastChecked: now,
      }
    }

    const trusted = activeModules.filter((m) => isKnownModule(chainId, m.value, m.name))
    const untrusted = activeModules.filter((m) => !isKnownModule(chainId, m.value, m.name))

    const moduleLabel = (m: { value: string; name?: string | null }) => m.name || `${m.value.slice(0, 10)}...`

    // Tier 2: All modules are trusted
    if (untrusted.length === 0) {
      return {
        status: 'clear',
        severity: 'Low',
        score: 100,
        evidence: trusted.map((m) => ({ label: 'Trusted module', value: moduleLabel(m) })),
        remediation: '',
        lastChecked: now,
      }
    }

    // Tier 3: Mix of trusted and untrusted
    if (trusted.length > 0 && untrusted.length === 1) {
      return {
        status: 'partial',
        severity: 'Medium',
        score: 50,
        evidence: [
          ...trusted.map((m) => ({ label: 'Trusted module', value: moduleLabel(m) })),
          ...untrusted.map((m) => ({ label: 'Unverified module', value: moduleLabel(m) })),
        ],
        remediation:
          'One installed module could not be verified as a known Safe ecosystem module. Review it in Settings to ensure it is from a trusted source.',
        lastChecked: now,
      }
    }

    // Tier 4: All untrusted, or more than 1 untrusted
    return {
      status: 'issue',
      severity: 'High',
      score: 20,
      evidence: [
        ...trusted.map((m) => ({ label: 'Trusted module', value: moduleLabel(m) })),
        ...untrusted.map((m) => ({ label: 'Unverified module', value: moduleLabel(m) })),
      ],
      remediation:
        'Unverified modules have full control over your Safe and can execute transactions without signer approval. Review and remove any modules you do not recognize.',
      lastChecked: now,
    }
  },
}

import type { SecurityScanner } from './types'

/**
 * Signer integrity scanner — checks whether Safe owners have exposure to
 * sanctioned or flagged sources.
 *
 * Currently returns `inconclusive` for all signers. The plan is to call a
 * CGW endpoint that proxies Blockaid's Risk Exposure API (server-side),
 * keeping API keys off the client. Once the CGW endpoint exists, this
 * scanner will be wired to it.
 */
export const signerIntegrityScanner: SecurityScanner = {
  id: 'signer_integrity',
  scan: async (ctx) => {
    const now = new Date().toISOString()

    // TODO: Replace with CGW endpoint call when available.
    // The endpoint should accept an array of signer addresses + chainId
    // and return per-signer risk exposure data (blocklist status, risk level,
    // exposure categories). Until then, return inconclusive so the UI shows
    // "Screening not yet available" rather than a false "all clear".
    return {
      status: 'inconclusive',
      severity: 'Low',
      score: 50,
      evidence: [
        { label: 'Status', value: 'Signer screening not yet available' },
        { label: 'Signers', value: `${ctx.owners.length}` },
      ],
      remediation: 'Signer screening will be available once the service integration is complete.',
      lastChecked: now,
    }
  },
}

